/** Full registry keyed by "toolGroup/action" */
export const COMMAND_REGISTRY = new Map<string, CommandMeta>(entries);

/** Short-name index: action -> "toolGroup/action" for non-ambiguous commands */
export const SHORT_NAMES = new Map<string, string>();

for (const [key, meta] of COMMAND_REGISTRY) {
  if (!meta.isAmbiguous) {
    SHORT_NAMES.set(meta.action, key);
  }
  const operationName = meta.operationId.replace(/^spacemolt_/, "");
  if (operationName !== meta.action) {
    SHORT_NAMES.set(operationName, key);
  }
}

